    "text_instructions": [
      {
        "id": "0000000000000000000000000000000d",
        "content": [
          "## General Instructions\r\n",
          "\r\n",
          "1. Always use DateID (INT, YYYYMMDD) for filtering - never Date (TIMESTAMP).\r\n",
          "\r\n",
          "2. Use customer_snapshot_v as primary dimension table. Join fact tables on RealCID+DateID.\r\n",
          "\r\n",
          "3. All monetary values are USD. Format as Currency ($).\r\n",
          "\r\n",
          "4. Revenue queries: default to IncludedInTotalRevenue = true.\r\n",
          "\r\n",
          "5. Period-end: use IsLastDayMonth/IsLastDayQuarter/IsLastDayYear flags.\r\n",
          "\r\n",
          "6. MIMO is sparse - rows only exist when activity occurred.\r\n",
          "\r\n",
          "7. AUM is daily snapshot for point-in-time analysis.\r\n",
          "\r\n",
          "8. Unique customers: COUNT(DISTINCT RealCID). Depositors: COUNT(DISTINCT DepositRealCID). Withdrawers: COUNT(DISTINCT WithdrawRealCID).\r\n",
          "\r\n",
          "9. Club tiers: Bronze < Silver < Gold < Platinum < Diamond.\r\n",
          "\r\n",
          "10. Active customers = PlayerStatusName not like '%blocked%'.\r\n",
          "\r\n",
          "11. De-duplication: Weekly=IsLastDayWeek, Monthly=IsLastDayMonth, Quarterly=IsLastDayQuarter, Yearly=IsLastDayYear.\r\n",
          "\r\n",
          "12. Date Formats: YYYYMMDD for filtering, YYYY-MM-DD for display.\r\n",
          "\r\n",
          "## Business Context\r\n",
          "\r\n",
          "eToro: global trading platform (stocks, crypto, indices, currencies, commodities, ETFs). Manual + Copy Trading.\r\n",
          "\r\n",
          "Club Tiers: loyalty (Bronze-Diamond). PI: IsPI=1 (GuruStatusID>1).\r\n",
          "\r\n",
          "Regulation: CySEC, FCA, ASIC, etc. MIMO: deposits/withdrawals by TradingPlatform vs eMoney.\r\n",
          "\r\n",
          "FTD: TotalFTDGlobalCount=1. AUM: EquityGlobal=total equity.\r\n",
          "\r\n",
          "Revenue: ConversionFee, RollOverFee, Commission, FullCommission, Dividends. IncludedInTotalRevenue=true for net.\r\n",
          "\r\n",
          "Active Traders: CountAsActiveTrade=1. Net Deposit: GlobalDepositsAmount - GlobalWithdrawsAmount."
        ]
      }
    ],
    "example_question_sqls": [
      {
        "id": "0000000000000000000000000000000e",
        "question": [
          "What was total net revenue last month by instrument type?"
        ],
        "sql": [
          "SELECT rev.InstrumentType, SUM(rev.RevenueAmount) AS TotalRevenue FROM main.etoro_kpi_stg.bi_output_vg_revenue_slim rev WHERE rev.IncludedInTotalRevenue = true AND rev.CalendarYearMonth = '2026-03' GROUP BY rev.InstrumentType ORDER BY TotalRevenue DESC"
        ]
      },
      {
        "id": "0000000000000000000000000000000f",
        "question": [
          "Monthly revenue trend for 2026, Trading vs Non-Trading"
        ],
        "sql": [
          "SELECT rev.CalendarYearMonth, rev.RevenueMetricCategory, SUM(rev.RevenueAmount) AS TotalRevenue FROM main.etoro_kpi_stg.bi_output_vg_revenue_slim rev WHERE rev.IncludedInTotalRevenue = true AND rev.CalendarYear = 2026 GROUP BY rev.CalendarYearMonth, rev.RevenueMetricCategory ORDER BY rev.CalendarYearMonth"
        ]
      },
      {
        "id": "00000000000000000000000000000010",
        "question": [
          "How many FTDs each month in 2026?"
        ],
        "sql": [
          "SELECT mimo.CalendarYearMonth, SUM(mimo.TotalFTDGlobalCount) AS FTD_Count, SUM(mimo.TotalFTDGlobalAmount) AS FTD_TotalAmount FROM main.etoro_kpi_stg.bi_output_vg_mimo_slim mimo WHERE mimo.CalendarYear = 2026 AND mimo.TotalFTDGlobalCount > 0 GROUP BY mimo.CalendarYearMonth ORDER BY mimo.CalendarYearMonth"
        ]
      },
      {
        "id": "00000000000000000000000000000011",
        "question": [
          "Total deposits and withdrawals by month this year"
        ],
        "sql": [
          "SELECT mimo.CalendarYearMonth, SUM(mimo.GlobalDepositsAmount) AS TotalDeposits, SUM(mimo.GlobalWithdrawsAmount) AS TotalWithdrawals, SUM(mimo.GlobalDepositsAmount) - SUM(mimo.GlobalWithdrawsAmount) AS NetDeposits FROM main.etoro_kpi_stg.bi_output_vg_mimo_slim mimo WHERE mimo.CalendarYear = 2026 GROUP BY mimo.CalendarYearMonth ORDER BY mimo.CalendarYearMonth"
        ]
      },
      {
        "id": "00000000000000000000000000000012",
        "question": [
          "Average global equity per customer by club tier end of last month"
        ],
        "sql": [
          "SELECT cs.ClubTier, COUNT(DISTINCT cs.RealCID) AS CustomerCount, AVG(aum.EquityGlobal) AS AvgGlobalEquity FROM main.etoro_kpi.customer_snapshot_v cs INNER JOIN main.etoro_kpi_stg.bi_output_vg_aum_slim aum ON cs.RealCID = aum.RealCID AND cs.DateID = aum.DateID WHERE cs.IsLastDayMonth = 1 AND cs.CalendarYearMonth = '2026-03' GROUP BY cs.ClubTier ORDER BY AvgGlobalEquity DESC"
        ]
      },
      {
        "id": "00000000000000000000000000000013",
        "question": [
          "Active customers per regulation as of latest month-end"
        ],
        "sql": [
          "SELECT cs.Regulation, COUNT(DISTINCT cs.RealCID) AS ActiveCustomers FROM main.etoro_kpi.customer_snapshot_v cs WHERE cs.IsLastDayMonth = 1 AND cs.PlayerStatusName not like '%blocked%' AND cs.CalendarYearMonth = '2026-03' GROUP BY cs.Regulation ORDER BY ActiveCustomers DESC"
        ]
      },
      {
        "id": "00000000000000000000000000000014",
        "question": [
          "Net deposit for Diamond-tier customers this quarter"
        ],
        "sql": [
          "SELECT cs.CalendarYearMonth, SUM(mimo.GlobalDepositsAmount) AS Deposits, SUM(mimo.GlobalWithdrawsAmount) AS Withdrawals, SUM(mimo.GlobalDepositsAmount) - SUM(mimo.GlobalWithdrawsAmount) AS NetDeposits FROM main.etoro_kpi.customer_snapshot_v cs INNER JOIN main.etoro_kpi_stg.bi_output_vg_mimo_slim mimo ON cs.RealCID = mimo.RealCID AND cs.DateID = mimo.DateID WHERE cs.ClubTier = 'Diamond' AND cs.CalendarQuarter = 1 AND cs.CalendarYear = 2026 GROUP BY cs.CalendarYearMonth ORDER BY cs.CalendarYearMonth"
        ]
      },
      {
        "id": "00000000000000000000000000000015",
        "question": [
          "Revenue per active customer by regulation last month"
        ],
        "sql": [
          "SELECT cs.Regulation, COUNT(DISTINCT cs.RealCID) AS ActiveCustomers, SUM(rev.RevenueAmount) AS TotalRevenue, SUM(rev.RevenueAmount) / COUNT(DISTINCT cs.RealCID) AS RevenuePerCustomer FROM main.etoro_kpi.customer_snapshot_v cs INNER JOIN main.etoro_kpi_stg.bi_output_vg_revenue_slim rev ON cs.RealCID = rev.RealCID AND cs.DateID = rev.DateID WHERE cs.PlayerStatusName not like '%blocked%' AND rev.IncludedInTotalRevenue = true AND cs.CalendarYearMonth = '2026-03' GROUP BY cs.Regulation ORDER BY RevenuePerCustomer DESC"
        ]
      }
    ],
